#include <omp.h>
#include <cmath>
#include <vector>
#include <limits>

struct Point {
	double x, y;
};

// Function to calculate the distance between two points
double distance(Point const& p1, Point const& p2) {
	return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

/* Return the distance between the closest two points in the vector points.
   Use OpenMP to compute in parallel. */
double closestPair(std::vector<Point> const& points) {
	if (points.size() < 2) return std::numeric_limits<double>::max(); // Handle edge cases

	double min_dist = std::numeric_limits<double>::max();
	int num_threads = omp_get_max_threads();

	// Parallel loop to compute distances between all pairs of points
	#pragma omp parallel for shared(points, min_dist) default(none) schedule(static)
	for (int i = 0; i < points.size(); ++i) {
		for (int j = i + 1; j < points.size(); ++j) {
			double dist = distance(points[i], points[j]);
			if (dist < min_dist) {
				#pragma omp critical
				{
					min_dist = dist;
				}
			}
		}
	}

	return min_dist;
}
